+            .edges
+            .iter()
+            .enumerate()
+            .map(|(edge_index, edge)| IrGraphEdge {
+                edge_id: edge_index,
+                from: edge.from,
+                to: edge.to,
+                span: edge.span,
+                ..IrGraphEdge::default()
+            })
