+    #[test]
+    fn equivalence_edit_undo_edit_cycle() {
+        let mut engine = IncrementalLayoutEngine::default();
+        let mut ir = large_two_subgraph_ir(32);
+        let config = super::LayoutConfig::default();
+        let guardrails = LayoutGuardrails::default();
